/**
 * Computes (base^exponent) % modulus
 * @param {bigint} base
 * @param {bigint} exponent
 * @param {bigint} modulus
 * @returns {bigint}
 */
function power(base, exponent, modulus) {
    let result = 1n;
    base %= modulus;
    while (exponent > 0n) {
        if (exponent % 2n === 1n) {
            result = (result * base) % modulus;
        }
        base = (base * base) % modulus;
        exponent /= 2n;
    }
    return result;
}

/**
 * Computes the modular multiplicative inverse of n modulo m
 * using Fermat's Little Theorem: n^(m-2) % m
 * Assumes m is prime.
 * @param {bigint} n
 * @param {bigint} modulus
 * @returns {bigint}
 */
function modInverse(n, modulus) {
    return power(n, modulus - 2n, modulus);
}

// Precompute factorials and inverse factorials for combinations
const MOD = 1000000007n;
const MAX_N = 100005;
const fact = new Array(MAX_N);
const invFact = new Array(MAX_N);

function precomputeFactorials() {
    fact[0] = 1n;
    for (let i = 1; i < MAX_N; i++) {
        fact[i] = (fact[i - 1] * BigInt(i)) % MOD;
    }
    invFact[MAX_N - 1] = modInverse(fact[MAX_N - 1], MOD);
    for (let i = MAX_N - 2; i >= 0; i--) {
        invFact[i] = (invFact[i + 1] * BigInt(i + 1)) % MOD;
    }
}

/**
 * Computes nCk % MOD
 * @param {number} n
 * @param {number} k
 * @returns {bigint}
 */
function combinations(n, k) {
    if (k < 0 || k > n) {
        return 0n;
    }
    if (k === 0 || k === n) {
        return 1n;
    }
    if (k > n / 2) {
        k = n - k;
    }
    // nCk = n! / (k! * (n-k)!)
    let res = fact[n];
    res = (res * invFact[k]) % MOD;
    res = (res * invFact[n - k]) % MOD;
    return res;
}

function solve(n, pos, k) {
    // Initialize factorials once if not already done (for contest environment safety)
    if (fact[0] === undefined) {
        precomputeFactorials();
    }

    // L_count: number of people to the left of pos (indices 0 to pos-1)
    const L_count = pos;
    // R_count: number of people to the right of pos (indices pos+1 to n-1)
    const R_count = n - 1 - pos;

    // --- Part 1: Left side (i < pos) ---
    // Visibility rule: i < pos is visible iff person i chooses 'L'.
    // We need to choose exactly 'k_L' people out of L_count to choose 'L'.
    // The remaining L_count - k_L people choose 'R' and are invisible.
    // The number of ways to achieve a specific k_L is C(L_count, k_L).

    // --- Part 2: Right side (i > pos) ---
    // Visibility rule: i > pos is visible iff person i chooses 'R'.
    // We need to choose exactly 'k_R' people out of R_count to choose 'R'.
    // The remaining R_count - k_R people choose 'L' and are invisible.
    // The number of ways to achieve a specific k_R is C(R_count, k_R).

    // --- Total Visibility ---
    // Total visible people = k_L + k_R. We require this to equal k.
    // k_L + k_R = k  =>  k_R = k - k_L

    let totalWays = 0n;

    // Iterate over all possible counts k_L from the left side (0 <= k_L <= L_count)
    for (let k_L = 0; k_L <= L_count; k_L++) {
        // Calculate the required count k_R for the right side
        const k_R = k - k_L;

        // Check if the required k_R is valid (0 <= k_R <= R_count)
        if (k_R >= 0 && k_R <= R_count) {
            // Ways to get k_L from the left: C(L_count, k_L)
            const ways_L = combinations(L_count, k_L);

            // Ways to get k_R from the right: C(R_count, k_R)
            const ways_R = combinations(R_count, k_R);

            // Contribution to total ways: ways_L * ways_R
            const contribution = (ways_L * ways_R) % MOD;
            totalWays = (totalWays + contribution) % MOD;
        }
    }

    // --- Part 3: Person at pos ---
    // The choice of direction for the person at 'pos' ('L' or 'R') does not affect 
    // the visibility count of others, as the visibility rules only depend on the 
    // choices of neighbors (i != pos).
    // Since there are 2 independent choices ('L' or 'R') for the person at pos, 
    // we multiply the result by 2.

    const finalResult = (totalWays * 2n) % MOD;

    return Number(finalResult);
}

